#include &lt;stdio.h&gt;
#include &lt;stdlib.h&gt;
#include &lt;pthread.h&gt;

#define ARRAY_SIZE 1000000
#define NUM_THREADS 4

int data_array[ARRAY_SIZE];

// The payload struct to pass multiple arguments into the thread
typedef struct {
    int thread_id;
    int start_index;
    int end_index;
    long long partial_sum;
} TaskData;

// The Thread Entry Point MUST match this exact signature
void* compute_quadrant(void* arg) {
    // Cast the opaque void pointer back to our structural type
    TaskData* task = (TaskData*)arg;
    task->partial_sum = 0;

    // Process strictly the specific quadrant assigned to this thread
    for (int i = task->start_index; i < task->end_index; i++) {
        task->partial_sum += data_array[i];
    }

    printf("Thread %d finished. Sum: %lld\n", task->thread_id, task->partial_sum);

    // Returning NULL. We could return a dynamically allocated pointer here.
    return NULL;
}

int main() {
    // Initialize dummy data
    for (int i = 0; i < ARRAY_SIZE; i++) data_array[i] = 1;

    pthread_t threads[NUM_THREADS];
    TaskData tasks[NUM_THREADS];
    int chunk_size = ARRAY_SIZE / NUM_THREADS;

    // 1. Spawning Phase
    for (int i = 0; i < NUM_THREADS; i++) {
        tasks[i].thread_id = i;
        tasks[i].start_index = i * chunk_size;
        tasks[i].end_index = (i + 1) * chunk_size;

        // Spawn the thread and hand it the memory address of its specific task struct
        if (pthread_create(&threads[i], NULL, compute_quadrant, &tasks[i]) != 0) {
            perror("Failed to spawn thread");
            return 1;
        }
    }

    // 2. Joining Phase
    // The main thread must halt and wait for all 4 workers to finish.
    // If main() exits, the OS instantly massacres all running threads.
    long long grand_total = 0;
    for (int i = 0; i < NUM_THREADS; i++) {
        pthread_join(threads[i], NULL);
        grand_total += tasks[i].partial_sum;
    }

    printf("Grand Total: %lld\n", grand_total);
    return 0;
}

#include &lt;pthread.h&gt;
#include &lt;stdio.h&gt;

void* worker(void* arg) {
    // DANGER: We dereference the pointer to get the ID
    int thread_id = *(int*)arg;
    printf("I am thread %d\n", thread_id);
    return NULL;
}

int main() {
    pthread_t threads[4];

    for (int i = 0; i < 4; i++) {
        // DANGER: We pass the memory address of the loop counter 'i'
        pthread_create(&threads[i], NULL, worker, &i);
    }

    for (int i = 0; i < 4; i++) pthread_join(threads[i], NULL);
    return 0;
}
